     4→interface ArticleListProps {
     5→  articles: ArticleProps[];
     6→  onArticleSelect?: (article: ArticleProps) => void;
     7→}
     8→
     9→const ArticleList: FC<ArticleListProps> = ({ articles, onArticleSelect }) => {
    10→  const handleKeyPress = (e: KeyboardEvent<HTMLLIElement>, article: ArticleProps) => {
    11→    if (e.key === 'Enter' || e.key === ' ') {
    12→      e.preventDefault();
    13→      onArticleSelect?.(article);
    14→    }
    15→  };
    16→
    17→  const handleClick = (article: ArticleProps) => {
    18→    onArticleSelect?.(article);
    19→  };
