    28→          <li 
    29→            key={index}
    30→            role="listitem"
    31→            tabIndex={0}
    32→            onClick={() => handleClick(article)}
    33→            onKeyPress={(e) => handleKeyPress(e, article)}
    34→            aria-label={`Article: ${article.title}`}
    35→          >
    36→            <Article {...article} />
